import{_ as l,c as a,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"版本历史: 更新记录 | Agent Skills","description":"查看 Agent Skills 的版本更新记录和功能变更历史。了解各版本的发布时间、新增功能、性能改进和问题修复详情。","frontmatter":{"title":"版本历史: 更新记录 | Agent Skills","sidebarTitle":"看看最近更新了什么","subtitle":"版本历史: 更新记录","description":"查看 Agent Skills 的版本更新记录和功能变更历史。了解各版本的发布时间、新增功能、性能改进和问题修复详情。","tags":["changelog","updates","releases"],"order":140},"headers":[],"relativePath":"zh/vercel-labs/agent-skills/changelog/releases/index.md","filePath":"zh/vercel-labs/agent-skills/changelog/releases/index.md"}'),r={name:"zh/vercel-labs/agent-skills/changelog/releases/index.md"};function n(o,e,s,d,c,h){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="版本历史" tabindex="-1">版本历史 <a class="header-anchor" href="#版本历史" aria-label="Permalink to &quot;版本历史&quot;">​</a></h1><p>本项目记录所有版本的功能更新、改进和修复。</p><hr><h2 id="v1-0-0-january-2026" tabindex="-1">v1.0.0 - January 2026 <a class="header-anchor" href="#v1-0-0-january-2026" aria-label="Permalink to &quot;v1.0.0 - January 2026&quot;">​</a></h2><h3 id="🎉-初始发布" tabindex="-1">🎉 初始发布 <a class="header-anchor" href="#🎉-初始发布" aria-label="Permalink to &quot;🎉 初始发布&quot;">​</a></h3><p>这是 Agent Skills 的第一个正式版本，包含完整的技能包和构建工具链。</p><h4 id="新增功能" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能" aria-label="Permalink to &quot;新增功能&quot;">​</a></h4><p><strong>React 性能优化规则</strong></p><ul><li>40+ 条 React/Next.js 性能优化规则</li><li>8 个主要类别：消除瀑布、打包优化、服务端性能、Re-render 优化等</li><li>按影响级别分类（CRITICAL &gt; HIGH &gt; MEDIUM &gt; LOW）</li><li>每条规则包含 Incorrect/Correct 代码示例对比</li></ul><p><strong>Vercel 一键部署</strong></p><ul><li>支持 40+ 种主流框架自动检测</li><li>零认证部署流程</li><li>自动生成预览链接和所有权转移链接</li><li>静态 HTML 项目支持</li></ul><p><strong>Web 设计指南</strong></p><ul><li>100+ 条 Web 界面设计规则</li><li>可访问性、性能、UX 多维度审查</li><li>远程拉取最新规则（从 GitHub）</li></ul><p><strong>构建工具链</strong></p><ul><li><code>pnpm build</code> - 生成 AGENTS.md 完整规则文档</li><li><code>pnpm validate</code> - 验证规则文件完整性</li><li><code>pnpm extract-tests</code> - 提取测试用例</li><li><code>pnpm dev</code> - 开发流程（build + validate）</li></ul><h4 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h4><ul><li>TypeScript 5.3.0</li><li>Node.js 20+</li><li>pnpm 10.24.0+</li><li>tsx 4.7.0 (TypeScript 执行时)</li></ul><h4 id="文档" tabindex="-1">文档 <a class="header-anchor" href="#文档" aria-label="Permalink to &quot;文档&quot;">​</a></h4><ul><li>AGENTS.md 完整规则指南</li><li>SKILL.md 技能定义文件</li><li>README.md 安装和使用说明</li><li>构建工具完整文档</li></ul><hr><h2 id="版本命名规范" tabindex="-1">版本命名规范 <a class="header-anchor" href="#版本命名规范" aria-label="Permalink to &quot;版本命名规范&quot;">​</a></h2><p>项目遵循语义化版本控制（Semantic Versioning）：</p><ul><li><strong>主版本号（Major）</strong>：不兼容的 API 变更</li><li><strong>次版本号（Minor）</strong>：向后兼容的新功能</li><li><strong>修订号（Patch）</strong>：向后兼容的问题修复</li></ul><p>示例：<code>1.0.0</code> 表示第一个稳定版本。</p>',24)])])}const g=l(r,[["render",n]]);export{u as __pageData,g as default};
